CHECKPOINT_PROCEDURE
BEGIN
 // Step 1: Write BEGIN_CHECKPOINT record
 writeLog(BEGIN_CHECKPOINT, current_timestamp)

 // Step 2: Write current transaction table
 FOR each active transaction T do
 writeLog(TRANSACTION_TABLE_ENTRY, T.id, T.status, T.lastLSN)
 END

 // Step 3: Write dirty page table
 FOR each dirty page P in buffer pool do
 writeLog(DIRTY_PAGE_TABLE_ENTRY, P.page_id, P.recLSN)
 END

 // Step 4: Flush all dirty pages to disk
 flushAllDirtyPages()

 // Step 5: Write END_CHECKPOINT record
 LSN = writeLog(END_CHECKPOINT, current_timestamp, LSN_of_BEGIN)
 flushLogToDisk()

 // Step 6: Store checkpoint location
 writeToMasterRecord(LSN)

 RETURN LSN
END

// Note: In fuzzy checkpointing, transactions can continue
// between steps 1-5, only step 3 (flush) needs to be atomic
// with actual checkpoint creation

// Undo with CLRs (Compensation Log Records)
UNDO_TRANSACTION(transaction_id)
BEGIN
 // Get transaction's last update LSN
 current_LSN = getLastLSN(transaction_id)

 WHILE current_LSN != NULL AND current_LSN.type != BEGIN DO

 IF current_LSN.type == UPDATE THEN

 // Step 1: Write CLR before undoing
 // CLR contains: transaction_id, prevLSN, undoNextLSN, page_id, old_value
 CLR_LSN = writeLog(
 CLR,
 transaction_id,
 current_LSN.prevLSN,
 current_LSN.page_id,
 current_LSN.old_value,
 "compensation_for_" + current_LSN.LSN
 )
 flushLogToDisk()

 // Step 2: Undo the update (restore old value)
 page = getPageFromBuffer(current_LSN.page_id)
 page.data = current_LSN.old_value
 markPageDirty(current_LSN.page_id)

 // Step 3: Update transaction table
 updateTransactionLastLSN(transaction_id, current_LSN.prevLSN)

 // Step 4: Move to previous update
 current_LSN = getLogRecord(current_LSN.prevLSN)

 ELSE IF current_LSN.type == CLR THEN
 // Already undone, follow undoNextLSN
 current_LSN = getLogRecord(current_LSN.undoNextLSN)
 END
 END

 // Write ABORT record
 writeLog(ABORT, transaction_id)
 flushLogToDisk()

 RETURN "Transaction undone"
END

// CLR is log record that survives crashes and helps
// avoid undoing same action twice during recovery
